                  {[1, 2, 3, 4, 5].map((star) => (
                    <span
                      key={star}
                      style={{
                        cursor: "pointer",
                        color: star <= reviewRating ? "#ffc107" : T.muted,
                        fontSize: 32,
                        userSelect: "none"
                      }}
                      onClick={() => setReviewRating(star)}
                    >
                      ★
                    </span>
                  ))}
                </div>
              </div>

              <div>
                <div style={{ fontSize: 12, fontWeight: 700, color: T.text, marginBottom: 6 }}>
                  Feedback Comments
