                  placeholder="Share your feedback, teaching style review, or encouraging remarks..."
                  value={reviewText}
                  onChange={(e) => setReviewText(e.target.value)}
                  style={{
                    width: "100%",
                    height: 100,
                    background: T.bg3,
                    border: `1px solid ${T.bg2}`,
                    borderRadius: 8,
                    color: T.text,
                    padding: 10,
                    fontSize: 13,
                    fontFamily: "inherit",
                    resize: "none",
                    outline: "none",
